// EF Core 9 breaking change: Migrate() now manages its own transactions
// internally.  Wrapping it in a user-opened transaction throws
// InvalidOperationException.  The execution strategy still retries on
// transient errors; the inner manual transaction must be removed.
void ApplyMigrations(AppDbContext db)
{
    var strategy = db.Database.CreateExecutionStrategy();
    strategy.Execute(() =>
    {
        db.Database.Migrate();
    });
}

